library(dplyr)
library(tidyr)
library(ggplot2)

claims_long <- dataset %>%
  select(
    year,
    liability_claims,
    liability_property_claims,
    liability_injury_claims,
    property_claims,
    theft_claims,
    fire_claims,
    glass_claims,
